  'w-mnsierwe-cdbf1c85b08d',
  'w-mnsifdm1-772730e8f865',
  'w-mnsifesq-5adb16b1395b',
];

// Parent/child mappings
const parentage = {
  'w-mnsidw40-be2f518f47b7': 'w-mnsiduuj-00d4de23230f', // detached-review → design
  'w-mnsidxaz-89f8c6dfdf9c': 'w-mnsiduuj-00d4de23230f', // detached-smoke → design
  'w-mnsifesq-5adb16b1395b': 'w-mnsifdm1-772730e8f865', // oculus-spec → brief
  'w-mnsierwe-cdbf1c85b08d': 'w-mnsidnza-d65bde46dffb', // patron-input early-spec → brief
};

const sel = db.prepare("SELECT content FROM books_clerk_writs WHERE id = ?");
const upd = db.prepare("UPDATE books_clerk_writs SET content = ? WHERE id = ?");

const tx = db.transaction(() => {
  for (const id of questIds) {
    const row = sel.get(id);
    if (!row) { console.log(`MISS ${id}`); continue; }
    const doc = JSON.parse(row.content);
    const before = doc.title;
    doc.title = doc.title.replace(/\s*\(historical\)\s*$/, '');
    if (parentage[id]) {
      doc.parentId = parentage[id];
    }
    doc.updatedAt = new Date().toISOString();
    upd.run(JSON.stringify(doc), id);
    const tag = parentage[id] ? ` [parent=${parentage[id].slice(0,12)}]` : '';
    console.log(`OK ${id}: "${before}" → "${doc.title}"${tag}`);
  }
});
tx();
db.close();
